26	// Resource contains the information required to scaffold files for a resource.
27	type Resource struct {
28		// GVK contains the resource's Group-Version-Kind triplet.
29		GVK `json:",inline"`
30	
31		// Plural is the resource's kind plural form.
32		Plural string `json:"plural,omitempty"`
33	
34		// Path is the path to the go package where the types are defined.
35		Path string `json:"path,omitempty"`
