58	// Validate checks that the Resource is valid.
59	func (r Resource) Validate() error {
60		// Validate the GVK
61		if err := r.GVK.Validate(); err != nil {
62			return err
63		}
64	
65		// Validate the Plural
66		// NOTE: IsDNS1035Label returns a slice of strings instead of an error, so no wrapping
67		if errors := validation.IsDNS1035Label(r.Plural); len(errors) != 0 {
68			return fmt.Errorf("invalid Plural: %#v", errors)
69		}
70	
71		// TODO: validate the path
72	
73		// Validate the API
74		if r.API != nil && !r.API.IsEmpty() {
75			if err := r.API.Validate(); err != nil {
76				return fmt.Errorf("invalid API: %w", err)
77			}
78		}
79	
80		// Validate the Webhooks
81		if r.Webhooks != nil && !r.Webhooks.IsEmpty() {
82			if err := r.Webhooks.Validate(); err != nil {
83				return fmt.Errorf("invalid Webhooks: %w", err)
84			}
85		}
86	
87		return nil
88	}
