331		if len(c.Plugins) == 0 {
332			return config.PluginKeyNotFoundError{Key: key}
333		}
334	
335		// Get the object blob by key and unmarshal into the object.
336		if pluginCfg, hasKey := c.Plugins[key]; hasKey {
337			b, err := yaml.Marshal(pluginCfg)
338			if err != nil {
339				return fmt.Errorf("failed to convert extra fields object to bytes: %w", err)
340			}
341			if err := yaml.Unmarshal(b, configObj); err != nil {
342				return fmt.Errorf("failed to unmarshal extra fields object: %w", err)
343			}
344			return nil
345		}
346	
347		return config.PluginKeyNotFoundError{Key: key}
348	}
