351	func (c *Cfg) EncodePluginConfig(key string, configObj any) error {
352		// Get object's bytes and set them under key in extra fields.
353		b, err := yaml.Marshal(configObj)
354		if err != nil {
355			return fmt.Errorf("failed to convert %T object to bytes: %w", configObj, err)
356		}
357		var fields map[string]any
358		if err := yaml.Unmarshal(b, &fields); err != nil {
359			return fmt.Errorf("failed to unmarshal %T object bytes: %w", configObj, err)
360		}
361		if c.Plugins == nil {
362			c.Plugins = make(map[string]pluginConfig)
363		}
364		c.Plugins[key] = fields
365		return nil
366	}
