370		for i, r := range c.Resources {
371			// If API is empty, omit it (prevents `api: {}`).
372			if r.API != nil && r.API.IsEmpty() {
373				c.Resources[i].API = nil
374			}
375			// If Webhooks is empty, omit it (prevents `webhooks: {}`).
376			if r.Webhooks != nil && r.Webhooks.IsEmpty() {
377				c.Resources[i].Webhooks = nil
378			}
379		}
380	
381		content, err := yaml.Marshal(c)
382		if err != nil {
383			return nil, config.MarshalError{Err: err}
384		}
385	
386		return content, nil
387	}
