390	func (c *Cfg) UnmarshalYAML(b []byte) error {
391		// Use non-strict unmarshaling to allow forward compatibility and external plugin fields.
392		// Older versions of kubebuilder should be able to read PROJECT files
393		// with newer fields and simply ignore unknown fields.
394		if err := yaml.Unmarshal(b, c); err != nil {
395			return config.UnmarshalError{Err: err}
396		}
397	
398		return nil
399	}
