	"sigs.k8s.io/kubebuilder/v4/pkg/machinery"
	"sigs.k8s.io/kubebuilder/v4/pkg/plugins/golang/v4/scaffolds/internal/templates/hack"
)

func TestBoilerplateUsesYearPlaceholder(t *testing.T) {
	template := &hack.Boilerplate{Owner: "The Kubernetes Authors"}
	if err := template.SetTemplateDefaults(); err != nil {
		t.Fatalf("SetTemplateDefaults() error = %v", err)
	}

	content, err := machinery.TemplateBodyForTest(template)
	if err != nil {
