func TestAPIScaffolderReplacesYearPlaceholderInBoilerplate(t *testing.T) {
	fs := afero.NewMemMapFs()
	if err := fs.MkdirAll("hack", 0o755); err != nil {
		t.Fatalf("MkdirAll() error = %v", err)
	}
	if err := afero.WriteFile(fs, hack.DefaultBoilerplatePath, []byte("/*\nCopyright YEAR The Kubernetes Authors.\n*/\n"), 0o644); err != nil {
		t.Fatalf("WriteFile() error = %v", err)
	}

	cfg := cfgv3.New()
	if err := cfg.SetRepository("example.com/project"); err != nil {
		t.Fatalf("SetRepository() error = %v", err)
	}
	res := resource.Resource{
		GVK: resource.GVK{Group: "crew", Domain: "example.com", Version: "v1", Kind: "Captain"},
		API: &resource.API{CRDVersion: "v1"},
	}

	scaffolder := NewAPIScaffolder(cfg, res, false)
	scaffolder.InjectFS(machinery.Filesystem{FS: fs})
	if err := scaffolder.Scaffold(); err != nil {
		t.Fatalf("Scaffold() error = %v", err)
	}

	content, err := afero.ReadFile(fs, "api/v1/captain_types.go")
	if err != nil {
		t.Fatalf("ReadFile() error = %v", err)
	}
	got := string(content)
	want := fmt.Sprintf("Copyright %d The Kubernetes Authors.", time.Now().Year())
	if !strings.Contains(got, want) {
		t.Fatalf("expected API file header to contain %q, got:\n%s", want, got)
	}
	if strings.Contains(got, "Copyright YEAR") {
		t.Fatalf("expected API file header not to contain unresolved YEAR, got:\n%s", got)
	}
}

